module accu(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [1:0] count;
reg [7:0] data_in_reg [3:0];
reg [9:0] accumulator;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 0;
        valid_out <= 0;
        data_out <= 0;
        accumulator <= 0;
        data_in_reg[0] <= 0;
        data_in_reg[1] <= 0;
        data_in_reg[2] <= 0;
        data_in_reg[3] <= 0;
    end else begin
        if (valid_in) begin
            data_in_reg[count] <= data_in;
            accumulator <= accumulator + data_in;
            count <= count + 1;
            if (count == 2) begin
                data_out <= accumulator;
                valid_out <= 1;
                accumulator <= 0;
            end else begin
                valid_out <= 0;
            end
        end else begin
            valid_out <= 0;
        end
    end
end

endmodule
